@app.route("/api/users/<user_id>", methods=["PUT"])
@require_admin_or_moderator
def update_user(user_id):
    current_user = g.current_user
    current_role = current_user["role"]
    current_role_level = ROLE_HIERARCHY.get(current_role, 0)

    # --- Object-level authorization: target user must exist ---
    target_user = users_db.get(user_id)
    if target_user is None:
        return jsonify({"error": "User not found"}), 404

    # --- Tenant scoping: admin/moderator can only manage users in their own tenant ---
    if target_user["tenant_id"] != current_user["tenant_id"]:
        # Return 404 instead of 403 to avoid leaking existence of cross-tenant users
        return jsonify({"error": "User not found"}), 404

    # --- Prevent self-modification through admin endpoint ---
    # Admins should not escalate their own role or change their own status
    # through this endpoint. Self-service changes should go through a
    # separate /api/users/me endpoint with its own rules.
    if target_user["id"] == current_user["id"]:
        return jsonify({"error": "Cannot modify your own account through this endpoint. Use /api/users/me instead."}), 403

    # --- Prevent privilege escalation: cannot modify users at or above your role level ---
    target_role_level = ROLE_HIERARCHY.get(target_user["role"], 0)
    if target_role_level >= current_role_level:
        return jsonify({"error": "Forbidden: cannot modify a user with equal or higher privileges"}), 403

    # --- Parse and validate request body ---
    data = request.get_json(silent=True)
    if not data or not isinstance(data, dict):
        return jsonify({"error": "Request body must be a JSON object"}), 400

    # --- Field allowlist: only permit fields the current role is allowed to change ---
    allowed_fields = ALLOWED_FIELDS_BY_ROLE.get(current_role, set())
    requested_fields = set(data.keys())
    disallowed_fields = requested_fields - allowed_fields

    if disallowed_fields:
        return jsonify({
            "error": f"You are not permitted to modify: {', '.join(sorted(disallowed_fields))}",
        }), 403

    if not requested_fields:
        return jsonify({"error": "No fields provided to update"}), 400

    # --- Prevent role escalation via assignment ---
    if "role" in data:
        new_role_level = ROLE_HIERARCHY.get(data["role"], 0)
        # Cannot assign a role equal to or above your own
        if new_role_level >= current_role_level:
            return jsonify({
                "error": "Forbidden: cannot assign a role equal to or above your own"
            }), 403

    # --- Validate each field value ---
    validated_updates = {}
    for field, value in data.items():
        is_valid, error_msg = validate_field_value(field, value)
        if not is_valid:
            return jsonify({"error": error_msg}), 400
        validated_updates[field] = value

    # --- Check uniqueness constraints ---
    if "email" in validated_updates:
        new_email = validated_updates["email"].lower().strip()
        for uid, u in users_db.items():
            if uid != user_id and u["email"].lower() == new_email and u["tenant_id"] == current_user["tenant_id"]:
                return jsonify({"error": "Email already in use"}), 409
        validated_updates["email"] = new_email

    if "username" in validated_updates:
        new_username = validated_updates["username"].strip()
        for uid, u in users_db.items():
            if uid != user_id and u["username"].lower() == new_username.lower() and u["tenant_id"] == current_user["tenant_id"]:
                return jsonify({"error": "Username already in use"}), 409
        validated_updates["username"] = new_username

    # --- Apply updates (only allowlisted, validated fields) ---
    for field, value in validated_updates.items():
        users_db[user_id][field] = value

    # --- Return safe representation (exclude sensitive fields) ---
    updated_user = dict(users_db[user_id])
    safe_response = {
        "id": updated_user["id"],
        "username": updated_user["username"],
        "email": updated_user["email"],
        "role": updated_user["role"],
        "account_status": updated_user["account_status"],
        "subscription_tier": updated_user["subscription_tier"],
    }

    return jsonify({"message": "User updated successfully", "user": safe_response}), 200


